1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 110;
3	
4	type Item = { type: string };
5	type Scenario = { steps: { items: Item[] }[] };
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	const policyBaseFor = (items: Item[]): number =>
15	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
16	
17	export const runScenario = (input: unknown): unknown => {
18	  const items = (input as Scenario).steps[0].items;
19	  const policyBase = policyBaseFor(items);
20	  const premium = Math.ceil((policyBase * FIRST_INSURANCE_PERCENT) / 100) + PROCESSING_FEE;
21	  return { results: [{ premium }] };
22	};
